import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';
import { Platform } from 'react-native';

// Configure notification handler
Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: true,
  }),
});

// Register for push notifications
export async function registerForPushNotificationsAsync() {
  if (!Device.isDevice) {
    Alert.alert('Must use a physical device for push notifications');
    return null;
  }

  const { status: existingStatus } = await Notifications.getPermissionsAsync();
  let finalStatus = existingStatus;

  if (existingStatus !== 'granted') {
    const { status } = await Notifications.requestPermissionsAsync();
    finalStatus = status;
  }

  if (finalStatus !== 'granted') return null;

  const tokenData = await Notifications.getExpoPushTokenAsync();

  // Android requires a notification channel
  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('default', {
      name: 'default',
      importance: Notifications.AndroidImportance.MAX,
    });
  }

  return tokenData.data;
}

// Handle incoming notifications
useEffect(() => {
  const foregroundSubscription = Notifications.addNotificationReceivedListener(
    (notification) => console.log('Notification received:', notification)
  );

  const responseSubscription = Notifications.addNotificationResponseReceivedListener(
    (response) => {
      const data = response.notification.request.content.data;
      if (data?.screen) {
        navigation.navigate(data.screen, { id: data.courseId });
      }
    }
  );

  return () => {
    foregroundSubscription.remove();
    responseSubscription.remove();
  };
}, []);

// Install: npm install @react-native-firebase/app @react-native-firebase/messaging

import messaging from '@react-native-firebase/messaging';

// Request permission
export async function requestNotificationPermission() {
  const authStatus = await messaging().requestPermission();
  const enabled =
    authStatus === messaging.AuthorizationStatus.AUTHORIZED ||
    authStatus === messaging.AuthorizationStatus.PROVISIONAL;
  return enabled;
}

// Get FCM Token
export async function getFCMToken() {
  const enabled = await requestNotificationPermission();
  if (!enabled) return null;

  const token = await messaging().getToken();
  await api.registerDeviceToken(token);
  return token;
}

// Listen for messages
useEffect(() => {
  // Token refresh
  const unsubscribeToken = messaging().onTokenRefresh(async (token) => {
    await api.registerDeviceToken(token);
  });

  // Foreground messages
  const unsubscribeMessage = messaging().onMessage(async (message) => {
    Toast.show({ title: message.notification?.title, body: message.notification?.body });
  });

  // Handle notification tap (from quit state)
  messaging().getInitialNotification().then((message) => {
    if (message) handleNotificationData(message.data);
  });

  return () => {
    unsubscribeToken();
    unsubscribeMessage();
  };
}, []);

// --- Typed Props ---
interface ButtonProps {
  title: string;
  onPress: () => void;
  variant?: 'primary' | 'secondary' | 'outline';
  disabled?: boolean;
  loading?: boolean;
  icon?: React.ReactNode;
  style?: StyleProp<ViewStyle>;
}

function Button({ title, onPress, variant = 'primary', disabled, loading, icon, style }: ButtonProps) {
  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      style={[styles.base, styles[variant], disabled && styles.disabled, style]}
    >
      {icon && <View style={{ marginRight: 8 }}>{icon}</View>}
      {loading ? <ActivityIndicator color="#fff" /> : <Text style={styles.text}>{title}</Text>}
    </TouchableOpacity>
  );
}

// --- Generic List Component ---
interface ListProps<T> {
  data: T[];
  renderItem: (item: T, index: number) => React.ReactNode;
  keyExtractor: (item: T) => string;
  emptyMessage?: string;
}

function List<T>({ data, renderItem, keyExtractor, emptyMessage }: ListProps<T>) {
  if (data.length === 0) return <Text>{emptyMessage || 'No items'}</Text>;
  return <>{data.map((item, index) => <View key={keyExtractor(item)}>{renderItem(item, index)}</View>)}</>;
}

